class Solution {
    public String reformatNumber(String number) {
        StringBuilder sb = new StringBuilder();
        for (char c : number.toCharArray()) {
            if (Character.isDigit(c)) {
                sb.append(c);
            }
        }
        String digits = sb.toString();
        List<String> blocks = new ArrayList<>();
        int i = 0;
        while (i < digits.length() - 4) {
            blocks.add(digits.substring(i, i + 3));
            i += 3;
        }
        if (digits.length() - i == 4) {
            blocks.add(digits.substring(i, i + 2));
            blocks.add(digits.substring(i + 2));
        } else if (digits.length() - i == 3) {
            blocks.add(digits.substring(i));
        } else if (digits.length() - i == 2) {
            blocks.add(digits.substring(i));
        }
        return String.join("-", blocks);
    }
}
